from flask import Flask, request, jsonify
from kafka import KafkaProducer
import json

app = Flask(__name__)

# Initialize Kafka producer
producer = KafkaProducer(
    bootstrap_servers='localhost:9092',
    value_serializer=lambda v: json.dumps(v).encode('utf-8')
)

@app.route('/publish', methods=['POST'])
def publish_message():
    try:
        data = request.json
        topic_name = data.get('topic')
        message = data.get('message')

        # Validate topic name and message
        if not topic_name or not isinstance(topic_name, str):
            return jsonify({'error': 'Invalid topic name'}), 400
        if not message:
            return jsonify({'error': 'Message content is required'}), 400

        # Publish message to the specified topic
        producer.send(topic_name, message)
        producer.flush()

        return jsonify({'status': 'Message sent successfully'}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

# Note: Ensure that the Kafka server is properly secured and configured to handle authentication and authorization.